def run():
    import os, re
    OUTPUT_DIR = 'email_drafts'
    path = f"{OUTPUT_DIR}/reponses.txt"
    if not os.path.exists(path):
        print(f"[ERREUR] Fichier introuvable: {path}")
        print("Lancez d'abord gmail_lire_et_repondre.")
        return []
    with open(path, 'r', encoding='utf-8') as f:
        content = f.read()
    # Decouper sur les blocs "=== MAIL N ==="
    blocks = re.split(r'(?=^=== MAIL \d+)', content, flags=re.MULTILINE)
    validated = []
    for block in blocks:
        if not block.strip().startswith('=== MAIL'):
            continue
        lines = block.strip().splitlines()
        headers = {}
        body_lines = []
        in_body = False
        for line in lines[1:]:  # saute la ligne "=== MAIL N ==="
            if line.strip() == '---':
                in_body = True
                continue
            if in_body:
                body_lines.append(line)
            else:
                m = re.match(r'^(A|Sujet|Message-ID|ENVOYER):\s*(.*)', line)
                if m:
                    headers[m.group(1)] = m.group(2).strip()
        if headers.get('ENVOYER', 'non').lower() == 'oui':
            validated.append({
                'to': headers.get('A', ''),
                'subject': headers.get('Sujet', ''),
                'message_id': headers.get('Message-ID', ''),
                'body': '\n'.join(body_lines).strip(),
            })
    print(f"[INFO] {len(validated)} reponse(s) a envoyer (ENVOYER: oui).")
    return validated
